// Declarando variáveis
let nome = 'Mariana';
nome = 'Mariana Silva'; // Permitido

const anoNascimento = 1998;
// anoNascimento = 2000; // Erro! Não pode reatribuir uma constante

const idade = 18;

if (idade >= 18) {
    console.log('Você é maior de idade.');
} else {
    console.log('Você é menor de idade.');
}

// Exemplo de loop for contando de 1 a 3
for (let i = 1; i <= 3; i++) {
    console.log('Contagem: ' + i);
}

// Declarando uma função de soma
function somar(a, b) {
    return a + b;
}

let resultado = somar(5, 10); // Chamada da função
console.log(resultado); // Exibe 15

// Capturando um elemento e alterando seu texto via DOM
const titulo = document.querySelector('h1');
titulo.innerText = 'Novo Título Interativo!';

// Exemplo de recursos modernos que mostram a evolução contínua da linguagem
const objetoComplexo = { dados: { valor: 42 } };
// Optional Chaining (?.) evita erros ao tentar ler propriedades nulas
console.log(objetoComplexo?.dados?.valor); // Saída: 42
console.log(objetoComplexo?.usuario?.nome); // Saída: undefined (sem quebrar o app)
